mapper.select:
SELECT 
FROM documents d
JOIN chunks c ON c.document_id = d.id
WHERE d.status = #{status}
  AND d.knowledge_folder_id = #{knowledgeFolderId}
ORDER BY d.updated_at DESC, c.chunk_index ASC

SELECT c.id AS chunk_id, c.document_id, c.chunk_index, c.content, c.content_hash, c.page_number, c.heading, d.file_name, d.source_path FROM chunks c JOIN documents d ON d.id = c.document_id LEFT JOIN knowledge_folders f ON f.id = d.knowledge_folder_id WHERE c.id IN
#{chunkId}
AND (d.knowledge_folder_id IS NULL OR f.enabled = 1)

mapper.update:
UPDATE documents
SET knowledge_folder_id = #{knowledgeFolderId}, updated_at = #{updatedAt}
WHERE id = #{documentId}

mapper.insert:
INSERT INTO chunks (
    id, document_id, chunk_index, content, content_hash,
    page_number, heading, token_count, created_at
)
VALUES (
    #{id}, #{documentId}, #{chunkIndex}, #{content}, #{contentHash},
    #{pageNumber}, #{heading}, #{tokenCount}, #{createdAt}
)

mapper.delete:
DELETE FROM chunks
WHERE document_id IN (
    SELECT id
    FROM documents
    WHERE knowledge_folder_id = #{knowledgeFolderId}
)
